--rollback DELETE FROM words WHERE word IN ('qualify','quantity','question','raise','range','rate','reach','reaction','real','realize','reason','receive','recognize','recommend','reflect','regard','relate','release','rely','remain','remove','replace','require','resolve','respond','result','retain','reveal','review','risk','role','scale','secure','select','separate','series','settle','severe','shift','significant','similar','situation','skill','solve','source','specific','standard','state','strategy','strength','structure','subject','succeed','suggest','supply','support','surface','surround','survey','survive','symbol','system');
